mapper.select:
SELECT * FROM train_user_skill
WHERE user_id = #{userId}
  AND skill_name = #{skillName}

mapper.update:
UPDATE train_user_skill
SET mastery_score = #{masteryScore},
    question_count = #{questionCount},
    last_practice_time = #{lastPracticeTime},
    update_time = #{updateTime}
WHERE id = #{id}

mapper.delete:
DELETE FROM train_user_skill
WHERE user_id = #{userId}
  AND skill_name = #{skillName}

mapper.select:
SELECT * FROM train_user_skill
WHERE user_id = #{userId}
  AND mastery_score > 0
ORDER BY mastery_score DESC
LIMIT #{limit}
